            kwargs['dim'] = axis
    elif like == 'autograd':
        if 'axis' not in kwargs and (kwargs.get('ord', None) is None or (kwargs.get('ord', None) is not None and np.ndim(tensor) == 1)):
            norm = _flat_autograd_norm
        else:
            from autograd.numpy.linalg import norm
